#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
const int N=2005;
ll n,k,siz[N],dp[N][N];
struct node
{
	int v,w;
};
vector<node> g[N];
void dfs(int u,int f)
{
	dp[u][0]=dp[u][1]=0;
	siz[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v,w=g[u][i].w;
		if(v==f) continue;
		dfs(v,u);
		siz[u]+=siz[v];
		for(int j=min(k,siz[u]);j>=0;j--)
		{
			if(dp[u][j]+1)
			{
				dp[u][j]+=(dp[v][0]+siz[v]*(n-k-siz[v])*w);
			}
			for(int kk=min(j,(int)siz[v]);kk>0;kk--)
			{
				if(dp[u][j-kk]+1)
				{
					dp[u][j]=max(dp[u][j],dp[u][j-kk]+dp[v][kk]+
					(kk*(k-kk)+(siz[v]-kk)*(n-k-siz[v]+kk))*w);
				}
			}
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>k;
	if(k>n-k) k=n-k;
	for(int i=1;i<n;i++)
	{
		int u,v,w;
		cin>>u>>v>>w;
		g[u].push_back(node{v,w});
		g[v].push_back(node{u,w});
	}
	memset(dp,-1,sizeof(dp));
	dfs(1,0);
	cout<<dp[1][k];
	return 0;
}
